css:
/* setting the image as the background of the form */
.fd-form  {
    box-sizing: border-box;
    background: url(https://plumsail.com/assets/forms/templates/event-registration-form-image-01.jpg) no-repeat center center fixed;
    background-size: auto;
    background-size: cover;
}


/* setting a transparent background for the Heading control */
.fd-form h1 > span,
.fd-form h4 > span,
.fd-form .fd-heading{
   background-color: transparent !important;;
}

/* setting the background of Grid container */
.fd-form .fd-blur-background{
    background: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(8px);
}

/* setting the the size of the iframe */
.fd-form .event-form iframe {
    width:100%;
    height:300px;
}
